export class IGraph{__canvas;__context=null;constructor(canvas){this.__canvas=canvas,void 0!==this.__canvas&&(this.__context=this.__canvas.getContext("2d"))}getColorFromColorRanges(colorRanges,value,defaultColor){if(colorRanges){let firstElemFromRange=colorRanges.find(elem=>!!elem.filterInstance&&elem.filterInstance.test(value));if(firstElemFromRange&&firstElemFromRange.color)return firstElemFromRange.color.color}return defaultColor}getFillColorFromColorRanges(colorRanges,value,defaultFillColor){if(colorRanges){let firstElemFromRange=colorRanges.find(elem=>!!elem.filterInstance&&elem.filterInstance.test(value));if(firstElemFromRange&&firstElemFromRange.fillColor)return firstElemFromRange.fillColor.color}return defaultFillColor}}